import { useMediaQuery } from './use-media-query';

export const useDeviceSize = () => {
	const isExtraSmallDevice = useMediaQuery('(max-width: 600px)');
	const isSmallDevice = useMediaQuery('(min-width : 601px) and (max-width : 960px)');
	const isMediumDevice = useMediaQuery('(min-width : 961px) and (max-width : 1200px)');
	const isLargeDevice = useMediaQuery('(min-width : 1201px) and (max-width : 1400px)');
	const isExtraLargeDevice = useMediaQuery('(min-width : 1401px) and (max-width : 1920px)');
	const isExtraExtraLargeDevice = useMediaQuery('(min-width : 1921px)');

	return {
		isExtraSmallDevice,
		isSmallDevice,
		isMediumDevice,
		isLargeDevice,
		isExtraLargeDevice,
		isExtraExtraLargeDevice,
	};
};
